input.old_string:
nixpkgs.config.allowUnfree = true;

# pnpm 10.29.2 is a build-time-only tool (fetches node_modules inside the Nix
# sandbox for signal-desktop and teleport); the binary never lands in the
# runtime closure, so the CVEs don't reach the running system. Drop this once
# those packages move to a non-insecure pnpm upstream.
nixpkgs.config.permittedInsecurePackages = [
  "pnpm-10.29.2"
];

toolUseResult.oldString:
nixpkgs.config.allowUnfree = true;

# pnpm 10.29.2 is a build-time-only tool (fetches node_modules inside the Nix
# sandbox for signal-desktop and teleport); the binary never lands in the
# runtime closure, so the CVEs don't reach the running system. Drop this once
# those packages move to a non-insecure pnpm upstream.
nixpkgs.config.permittedInsecurePackages = [
  "pnpm-10.29.2"
];

toolUseResult.originalFile:
{
  inputs,
  pkgs,
  nixpkgs-unstable,
  config,
  lib,
  ...
}:
let
  binDir = "/etc/profiles/per-user/eldios/bin";
in
{
  zramSwap = {
    enable = true;
    algorithm = "zstd";
    memoryPercent = 10;
  };

  systemd.services.zfs-mount.enable = false;
  systemd.services.NetworkManager-wait-online.enable = false;

  # nixpkgs configuration moved to avoid warning with home-manager.useGlobalPkgs
  # Overlays are now applied through nixpkgs.overlays at host level
  nixpkgs.config.allowUnfree = true;

  # pnpm 10.29.2 is a build-time-only tool (fetches node_modules inside the Nix
  # sandbox for signal-desktop and teleport); the binary never lands in the
  # runtime closure, so the CVEs don't reach the running system. Drop this once
  # those packages move to a non-insecure pnpm upstream.
  nixpkgs.config.permittedInsecurePackages = [
    "pnpm-10.29.2"
  ];

  # nix
  nix = {
    # This will add each flake input as a registry
    # To make nix3 commands consistent with your flake
    registry = lib.mapAttrs (_: value: { flake = value; }) inputs;
    # This will additionally add your inputs to the system's legacy channels
    # Making legacy nix commands consistent as well, awesome!
    nixPath = lib.mapAttrsToList (key: value: "${key}=${value.to.path}") config.nix.registry;
    gc = {
      automatic = true;
      persistent = true;
      dates = "weekly";
      options = "--delete-older-than 31d";
    };
    extraOptions = ''
      !include ${config.sops.secrets."tokens/github/nix".path}
    '';
    settings = {
      # Nix Settings
      auto-optimise-store = true; # Auto Optimize nix store.
      experimental-features = [
        "nix-command"
        "flakes"
      ]; # Enable experimental features.
      trusted-users = [
        "root"
        "eldios"
      ];
      substituters = [
        "https://cache.nixos.org"
        "https://nix-community.cachix.org"
      ];
      trusted-public-keys = [
        "cache.nixos.org-1:REDACTED"
        "nix-community.cachix.org-1:REDACTED/rkCWyvRCYg3Fs="
      ];
    };
  };

  services = {
    fwupd.enable = true;

    fail2ban = {
      enable = true;
      # Ban IP after 5 failures
      maxretry = 5;
      ignoreIP = [
        # Whitelist some subnets
        "192.168.152.0/21"
      ];
      bantime = "24h"; # Ban IPs for one day on the first ban
      bantime-increment = {
        enable = true; # Enable increment of bantime after each violation
        # formula = "ban.Time * math.exp(float(ban.Count+1)*banFactor)/math.exp(1*banFactor)";
        multipliers = "1 2 4 8 16 32 64";
        maxtime = "168h"; # Do not ban for more than 1 week
        overalljails = true; # Calculate the bantime based on all the violations
      };

    };

    openssh = {
      enable = true;
      openFirewall = true;
      settings = {
        PermitRootLogin = "prohibit-password";
        PasswordAuthentication = false;
        KbdInteractiveAuthentication = false;
        AllowAgentForwarding = true;
      };
    };

    smartd = {
      enable = true;
      autodetect = true;
    };

    fstrim = {
      enable = true;
      interval = "daily";
    };

    pcscd.enable = true;

    tailscale = {
      enable = true;
      package = pkgs.unstable.tailscale;
    };

  };

  programs.nix-ld = {
    enable = true;
    libraries = [ ];
  };

  # nh: modern wrapper around nixos-rebuild / home-manager / nix-collect-garbage.
  # Existing `nixu` alias (sudo -E nixos-rebuild switch --flake ~/dotfiles)
  # keeps working in parallel. Try: `nh os switch ~/dotfiles`,
  # `nh clean all --keep 5`, `nh search <pkg>`.
  # nh.clean.enable left off because nix.gc.automatic above already
  # handles GC weekly; nh would conflict with the warning.
  programs.nh = {
    enable = true;
    flake = "/home/eldios/dotfiles";
  };

  environment.shells = [
    "${binDir}/nu"
  ];

  programs.zsh = {
    enable = true;
  };

  environment.systemPackages = with pkgs; [
    # basic shell pkgs
    bash

    # hard reqs
    binutils
    borgbackup
    btrfs-progs
    git
    gptfdisk
    libgcc
    nix-tree
    pinentry-curses # required by GPG
    python3
    restic
    ripgrep
    screen
    smartmontools
    sshuttle
    proxychains-ng
    tmux
    wget
    wireguard-tools

    # utils
    age
    btop
    byobu
    #colorls # like `ls --color=auto -F` but cooler
    ethtool
    fastfetch
    file
    ffmpeg
    gnumake
    htop
    just
    lsd
    lshw
    manix
    mdadm
    openssl
    rclone
    sops
    ssh-to-age
    xxd
    yubikey-manager # `ykman` — FIDO2/PIV/OATH/OTP management (PIN, reset, info)
    yubikey-personalization

    # WAYLAND + SWAY
    dbus # make dbus-update-activation-environment available in the path
    glib # gsettings

    # keyboard related stuff
    gvfs
    jmtpfs
    qmk
    qmk-udev-rules
    qmk_hid
    sof-firmware
    v4l-utils
    via
    vial
  ];

  hardware.keyboard.qmk.enable = true;
  services.udev.packages = with pkgs; [
    qmk
    qmk-udev-rules
    qmk_hid
    vial
    via
    yubikey-personalization # udev rules for non-root Yubikey (FIDO2/OTP) access
  ];

  security = {
    polkit.enable = true;

    sudo = {
      enable = true;
      wheelNeedsPassword = false;
    };
  };
}

