    # basic shell pkgs
    bash

    # hard reqs
    binutils
    borgbackup
    btrfs-progs
    git
    gptfdisk
    libgcc
    nix-tree
    pinentry-curses # required by GPG
    python3
    restic
    ripgrep
    screen
    smartmontools
    sshuttle
    proxychains-ng
    tmux
    wget
    wireguard-tools

    # utils
    age
    btop
    byobu
    #colorls # like `ls --color=auto -F` but cooler
    ethtool
    fastfetch
    file
    ffmpeg
    gnumake
    htop
    just
    lsd
    lshw
    manix
    mdadm
    openssl
    rclone
    sops
    ssh-to-age
    xxd
    yubikey-manager # `ykman` — FIDO2/PIV/OATH/OTP management (PIN, reset, info)
    yubikey-personalization

    # WAYLAND + SWAY
    dbus # make dbus-update-activation-environment available in the path
    glib # gsettings

    # keyboard related stuff
    gvfs
    jmtpfs
    qmk
    qmk-udev-rules
    qmk_hid
    sof-firmware
    v4l-utils
    via
    vial
  ];

  hardware.keyboard.qmk.enable = true;
  services.udev.packages = with pkgs; [
    qmk
    qmk-udev-rules
    qmk_hid
    vial
    via
    yubikey-personalization # udev rules for non-root Yubikey (FIDO2/OTP) access
  ];

  security = {
    polkit.enable = true;

    sudo = {
      enable = true;
      wheelNeedsPassword = false;
    };
  };
}

