# Communication
# mailspring builds from source; electron-packager deadlocks under libuv
# io_uring on recent kernels, so force the threadpool path during build.
(mailspring.overrideAttrs (old: {
  preBuild = (old.preBuild or "") + ''
    export UV_USE_IO_URING=0
  '';
})) # mailclient

